function invertBinaryTree(data) {
    if (!data) return null;
    const nodes = data.split(' ').map(Number);

    function buildTree(index) {
        if (index >= nodes.length || nodes[index] === null) return null;
        const node = { val: nodes[index], left: null, right: null };
        node.left = buildTree(2 * index + 1);
        node.right = buildTree(2 * index + 2);
        return node;
    }

    function invert(node) {
        if (!node) return null;
        const temp = node.left;
        node.left = invert(node.right);
        node.right = invert(temp);
        return node;
    }

    function levelOrder(node) {
        const result = [];
        const queue = [node];
        while (queue.length) {
            const current = queue.shift();
            if (current) {
                result.push(current.val);
                queue.push(current.left);
                queue.push(current.right);
            }
        }
        return result;
    }

    const root = buildTree(0);
    const invertedRoot = invert(root);
    return levelOrder(invertedRoot).join(' ');
}

