func invertBinaryTree(data *TreeNode) *TreeNode {
    if data == nil {
        return nil
    }

    queue := []*TreeNode{data}

    for len(queue) > 0 {
        node := queue[0]
        queue = queue[1:]

        node.Left, node.Right = node.Right, node.Left

        if node.Left != nil {
            queue = append(queue, node.Left)
        }
        if node.Right != nil {
            queue = append(queue, node.Right)
        }
    }

    return data
}

